operations.insert:
#statusBox.hidden {
  display: none !important;
}

.session-restore-note {
  width: min(85%, 1380px);
  margin: 14px auto 26px;
  text-align: center;
  font-size: 12.5px;
  line-height: 1.4;
  color: #94a3b8;
  font-weight: 520;
}

.session-restore-note.hidden {
  display: none !important;
}

operations.old:
if (state.rows.length > 0) {
  setStatus("Saved data from the previous session has been loaded.", "info");
}

operations.new:
if (state.rows.length > 0) {
  statusBox.classList.add("hidden");
  sessionRestoreNotice.textContent = "Saved data from the previous session has been loaded.";
  sessionRestoreNotice.classList.remove("hidden");
}

operations.old:
function setStatus(message, tone) {
  statusBox.textContent = message;
  statusBox.className = "status " + tone;
}

operations.new:
function setStatus(message, tone) {
  statusBox.textContent = message;
  statusBox.className = "status " + tone;
  sessionRestoreNotice.classList.add("hidden");
}
